INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Bent Over Row', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['Set the barbell attached to the smith machine to a height that is about 2 inches below your knees.','Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up.','Now grasp the barbell using an overhand (pronated) grip and unlock it from the smith machine rack. Then let it hang directly in front of you as your arms hang extended perpendicular to the floor and your torso. This is your starting position.','While keeping the torso stationary, lift the barbell as you breathe out, keeping the elbows close to the body and not doing any force with the forearm other than holding the weights. On the top contracted position, squeeze the back muscles and hold for a second.','Slowly lower the weight again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Calf Raise', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Place a block or weight plate below the bar on the Smith machine. Set the bar to a position that best matches your height. Once the correct height is chosen and the bar is loaded, step onto the plates with the balls of your feet and place the bar on the back of your shoulders.','Take the bar with both hands facing forward. Rotate the bar to unrack it. This will be your starting position.','Raise your heels as high as possible by pushing off of the balls of your feet, flexing your calf at the top of the contraction. Your knees should remain extended. Hold the contracted position for a second before you start to go back down.','Return slowly to the starting position as you breathe in while lowering your heels.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Close-Grip Bench Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Place a flat bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a close and pronated grip (palms facing forward) that is around shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, lock the bar back in the rack.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Decline Press', 'machine', true, 'machine', 'beginner', NULL, 'compound', ARRAY['Position a decline bench in the rack so that the bar will be above your chest. Load an appropriate weight and take your place on the bench.','Rotate the bar to unhook it from the rack and fully extend your arms. Your back should be slightly arched and your shoulder blades retracted. This will be your starting position.','Begin the movement by flexing your arms, lowering the bar to your chest.','Pause briefly, and then extend your arms to push the weight back to the starting position.','After completing the desired number of repetitions, rotate the bar to rack the weight.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Hang Power Clean', 'machine', true, 'machine', 'intermediate', 'pull', 'compound', ARRAY['Position the bar at knee height and load it to an appropriate weight.','Take a pronated grip on the bar outside of shoulder width and unhook the bar from the machine. Your arms should be fully extended with your head and chest up. Your elbows should be pointed out with your shoulders back and down. Your hips should be back, loading the tension into the hamstrings. This will be your starting position.','Initate the movement by forcefully extending the hips and knees, accelerating into the bar. Ensure that you keep your arms straight during this part of the motion.','Upon full extension, rebend the hips and knees to lower your receiving position.','Allow the arms to flex at this point, rotating the elbows around the bar to receive it on your shoulders.','Extend through the hips and knees to come to a standing position with the bar racked on your shoulders to complete the movement.'], ARRAY['hamstrings'], ARRAY['glutes','lower back','quadriceps','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Hip Raise', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['Position a bench in the rack and load the bar to an appropriate weight. Lie down on the bench, placing the bottom of your feet against the bar. Unlock the bar and extend your legs. You may need to use your hands to assist you. For added stability grasp the sides of the Smith Machine. This will be your starting position.','Initiate the movement by rotating your pelvis, flexing your spine to raise your hips off of the bench. Maintain a slight bend in the knees throughout the motion.','After a brief pause, return the hips to the bench.','Repeat for the desired number of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Incline Bench Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Place an incline bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the incline bench and make sure your upper chest is aligned with the barbell. Using a pronated grip (palms facing forward) that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your upper chest.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Leg Press', 'machine', true, 'machine', 'intermediate', 'push', 'compound', ARRAY['Position a Smith machine bar a couple feet off of the ground. Ensure that it is resting on the safeties. After loading the bar to an appropriate weight, lie underneath the bar. Place the middle of your feet on the bar, tucking your knees to your chest. This will be your starting position.','Begin the movement by driving through your feet to move the bar upward, extending the hips and knees. Do not lock out your knees.','At the top of the motion, pause briefly before returning to the starting position.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine One-Arm Upright Row', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['With the bar at thigh level, load an appropriate weight.','Take a wide grip on the bar and unhook the weight, removing your off hand from the bar. Your arm should be extended as you stand up straight with your head and chest up. This will be your starting position.','Begin the movement by flexing the elbow, raising the upper arm with the elbow pointed out. Continue until your upper arm is parallel to the floor.','After a brief pause, return the weight to the starting position.','Repeat for the desired number of repetitions before engaging the hooks to rack the weight.'], ARRAY['shoulders'], ARRAY['biceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Overhead Shoulder Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['To begin, place a flat bench (or preferably one with back support) underneath a smith machine. Position the barbell at a height so that when seated on the flat bench, the arms must be almost fully extended to reach the barbell.','Once you have the correct height, sit slightly in behind the barbell so that there is an imaginary straight line from the tip of your nose to the barbell. Your feet should be stationary. Grab the barbell with the palms facing forward, unlock it and lift it up so that your arms are fully extended. This is the starting position.','Slowly begin to lower the barbell until it is level with your chin while inhaling.','Then lift the barbell back to the starting position using your shoulders while exhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Pistol Squat', 'machine', true, 'machine', 'intermediate', 'push', 'compound', ARRAY['To begin, first set the bar to a position that best matches your height. Step under it and position the bar across the back of your shoulders.','Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs. 3','Move one foot forward about 12 inches in front of the bar. Extend the other leg out in front of you, holding it off the ground. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position.','Maintaining good posture, lower yourself by flexing the knee and hip, going down as far as flexibility allows.','Pause briefly at the bottom and then return to the starting position by driving through the heel of your foot, extending the knee and hip.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Reverse Calf Raises', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Adjust the barbell on the smith machine to fit your height and align a raised platform right under the bar.','Stand on the platform with the heels of your feet secured on top of it with the balls of your feet extending off it. Position your toes facing forward with a shoulder width stance.','Now, place your shoulders under the barbell while maintaining the foot positioning described and push the barbell up by extending your hips and knees until your torso is standing erect. The knees should be kept with a slight bend; never locked. This will be your starting position. Tip: The barbell on your back is only for balance purposes.','Raise the balls of your feet as you breathe out by extending your toes as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position for a second before you start to go back down.','Slowly go back down to the starting position as you breathe in by lowering the balls of your feet and toes.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Squat', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['To begin, first set the bar on the height that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side (palms facing forward), unlock it and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance which targets overall development; however you can choose any of the three stances discussed in the foot stances section).','Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as you exhale by pushing the floor with the heel of your foot as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Stiff-Legged Deadlift', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['To begin, set the bar on the smith machine to a height that is around the middle of your thighs. Once the correct height is chosen and the bar is loaded, grasp the bar using a pronated (palms forward) grip that is shoulder width apart. You may need some wrist wraps if using a significant amount of weight.','Lift the bar up by fully extending your arms while keeping your back straight. Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.','Keeping the knees stationary, lower the barbell to over the top of your feet by bending at the waist while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Exhale as you perform this movement','Start bringing your torso up straight again as soon as you feel the hamstrings stretch by extending your hips and waist until you are back at the starting position. Inhale as you perform this movement.','Repeat for the recommended amount of repetitions.'], ARRAY['hamstrings'], ARRAY['glutes','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Upright Row', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['To begin, set the bar on the smith machine to a height that is around the middle of your thighs. Once the correct height is chosen and the bar is loaded, grasp the bar using a pronated (palms forward) grip that is shoulder width apart. You may need some wrist wraps if using a significant amount of weight.','Lift the barbell up and fully extend your arms with your back straight. There should be a slight bend at the elbows. This is the starting position.','Use your side shoulders to lift the bar as you exhale. The bar should be close to the body as you move it up. Continue to lift it until it nearly touches your chin. Tip: Your elbows should drive the motion. As you lift the bar, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the bar back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY['biceps','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Single-Leg Split Squat', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['To begin, place a flat bench 2-3 feet behind the smith machine. Then, set the bar on the height that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side (palms facing forward), unlock it and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Position your legs by placing one foot slightly forward under the bar and extending your other leg back and place the top of your foot on the bench. This will be your starting position','Begin to slowly lower the bar by bending the knee as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calf becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knee should make an imaginary straight line with the toes that is perpendicular to the front. If your knee is past that imaginary line (if it is past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as you exhale by pushing the floor with the heel of your foot mainly as you straighten your leg again and go back to the starting position.','Repeat for the recommended amount of repetitions.','Switch legs and repeat the movement.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Snatch', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Place your feet at a shoulder width stance with the barbell resting right above the connection between the toes and the rest of the foot.','With a palms facing down grip, bend at the knees and keeping the back flat grab the bar using a wider than shoulder width grip. Bring the hips down and make sure that your body drops as if you were going to sit on a chair. This will be your starting position.','Start pushing the floor as if it were a moving platform with your feet and simultaneously start lifting the barbell keeping it close to your legs.','As the bar reaches the middle of your thighs, push the floor with your legs and lift your body to a complete extension in an explosive motion.','Lift your shoulders back in a shrugging movement as you bring the bar up while lifting your elbows out to the side and keeping them above the bar for as long as possible.','Now in a very quick but powerful motion, you have to get your body under the barbell when it has reached a high enough point where it can be controlled and drop while locking your arms and holding the barbell overhead as you assume a squat position.','Finalize the movement by rising up out of the squat position to finish the lift. At the end of the lift both feet should be on line and the arms fully extended holding the barbell overhead.'], ARRAY['quadriceps'], ARRAY['biceps','glutes','hamstrings','lower back','shoulders','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Snatch Balance', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin with the feet in the pulling position, the bar racked across the back of the shoulders, and the hands placed in a wide snatch grip.','Pop the bar with an abrupt dip and drive of the knees, and aggressively drive under the bar, transitioning the feet into the receiving position.','Receive the bar locked out overhead near the bottom of the squat. The torso should remain vertical, lowering the hips between the legs.','Continue to descend to full depth, and return to a standing position. Carefully lower the weight.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Snatch Deadlift', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['The snatch deadlift strengthens the first pull of the snatch. Begin with a wide snatch grip with the barbell placed on the platform. The feet should be directly under the hips, with the feet turned out. Squat down to the bar, keeping the back in absolute extension with the head facing forward.','Initiate the movement by driving through the heels, raising the hips. The back angle should remain the same until the bar passes the knees.','At that point, drive your hips through the bar as you lay back. Return the bar to the platform by reversing the motion.'], ARRAY['hamstrings'], ARRAY['forearms','glutes','hamstrings','lower back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Snatch Pull', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['With a barbell on the floor close to the shins, take a wide snatch grip. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.','Next comes the second pull, the main source of acceleration for the pull. As the bar approaches the mid-thigh position, begin extending through the hips. In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward.','There should be no need to actively pull through the arms to accelerate the weight; at the end of the second pull, the body should be fully extended, leaning slightly back. Full extension should be violent and abrupt, and ensure that you do not prolong the extension for longer than necessary.'], ARRAY['hamstrings'], ARRAY['calves','glutes','lower back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Snatch Shrug', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin with a wide grip, with the bar hanging at the mid thigh position. You can use a hook or overhand grip. Your back should be straight and inclined slightly forward.','Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a snatch, avoid overloading to the point that the execution slows down.'], ARRAY['traps'], ARRAY['forearms','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Snatch from Blocks', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Begin with a loaded barbell on boxes or stands of the desired height. A wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar, with the elbows pointed out. This will be the starting position.','Begin the first pull by driving through the front of the heels, raising the bar from the boxes.','Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. The feet should move to just outside the hips, turned out as necessary. Receive the bar with your body as low as possible and the arms fully extended overhead.','Keeping the bar aligned over the front of the heels, your head and chest up, drive through heels of the feet to move to a standing position. Carefully return the weight to the boxes.'], ARRAY['quadriceps'], ARRAY['calves','forearms','glutes','hamstrings','lower back','shoulders','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Speed Band Overhead Triceps', 'bands', true, 'bands', 'beginner', 'push', 'isolation', ARRAY['For this exercise anchor a band to the ground. We used an incline bench and anchored the band to the base, standing over the bench. Alternatively, this could be performed standing on the band.','To begin, pull the band behind your head, holding it with a pronated grip and your elbows up. This will be your starting position.','To perform the movement, extend through the elbow to to straighten your arms, ensuring that you keep your upper arm in place.','Pause, and then return to the starting position.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Speed Box Squat', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Attach bands to the bar that are securely anchored near the ground. You may need to choke the bands to get adequate tension.','Use a box of an appropriate height for this exercise. Load the bar to a weight that still requires effort, but isn''t so heavy that speed is compromised. Typically, that will be between 50-70% of your one rep max.','Position the bar on your upper back, shoulder blades retracted, back arched and everything tight head to toe. This will be the starting position.','Unrack the bar and position yourself in front of the box. Sit back with your hips until you are seated on the box, ensuring that you descend under control and don''t crash onto the surface.','Pause briefly, and explode off of the box, extending through the hips and knees.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Speed Squats', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance which targets overall development; however you can choose any of the three stances discussed in the foot stances section).','Begin to lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as fast as possible without involving momentum as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position. Note: You should perform these exercises as fast as possible but without breaking perfect form and without involving momentum.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Spell Caster', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Hold a dumbbell in each hand with a pronated grip. Your feet should be wide with your hips and knees extended. This will be your starting position.','Begin the movement by pulling both of the dumbbells to one side next to your hip, rotating your torso.','Keeping your arms straight and the dumbbells parallel to the ground, rotate your torso to swing the weights to your opposite side.','Continue alternating, rotating from one side to the other until the set is complete.'], ARRAY['abdominals'], ARRAY['glutes','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Spider Crawl', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Begin in a prone position on the floor. Support your weight on your hands and toes, with your feet together and your body straight. Your arms should be bent to 90 degrees. This will be your starting position.','Initiate the movement by raising one foot off of the ground. Externally rotate the leg and bring the knee toward your elbow, as far forward as possible.','Return this leg to the starting position and repeat on the opposite side.'], ARRAY['abdominals'], ARRAY['chest','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Spider Curl', 'e-z curl bar', true, 'e-z curl bar', 'beginner', 'pull', 'isolation', ARRAY['Start out by setting the bar on the part of the preacher bench that you would normally sit on. Make sure to align the barbell properly so that it is balanced and will not fall off.','Move to the front side of the preacher bench (the part where the arms usually lay) and position yourself to lay at a 45 degree slant with your torso and stomach pressed against the front side of the preacher bench.','Make sure that your feet (especially the toes) are well positioned on the floor and place your upper arms on top of the pad located on the inside part of the preacher bench.','Use your arms to grab the barbell with a supinated grip (palms facing up) at about shoulder width apart or slightly closer from each other.','Slowly begin to lift the barbell upwards and exhale. Hold the contracted position for a second as you squeeze the biceps.','Slowly begin to bring the barbell back to the starting position as your breathe in. .','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Split Clean', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['With a barbell on the floor close to the shins, take an overhand grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.','Next comes the second pull, the main source of acceleration for the clean. As the bar approaches the mid-thigh position, begin extending through the hips. In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight; at the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.','As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, aggressively pull yourself down, rotating your elbows under the bar as you do so.','Receive the bar with the feet split, aggressively moving one foot forward and one foot back. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom position, which will help in the recovery.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Bring the feet together as you stand up.'], ARRAY['quadriceps'], ARRAY['calves','forearms','glutes','hamstrings','lower back','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Split Jerk', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward.','Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders. At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible.','In the brief moment the feet are not actively driving against the platform, the athlete''s effort to push the bar up will drive them down. The feet should be moved to a split stance, one foot forward, one foot back, with the knees partially bent. Receive the bar with the arms locked out overhead.','Return to a standing position, bringing the feet together.'], ARRAY['quadriceps'], ARRAY['glutes','hamstrings','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Split Jump', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.','Ensure that the front knee is over the midline of the foot.','Extending through both legs, jump as high as possible, swinging your arms to gain lift.','As you jump, bring your feet together, and move them back to their initial positions as you land.','Absorb the impact by reverting back to the starting position.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Split Snatch', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Begin with a loaded barbell on the floor. The bar should be close to or touching the shins, and a wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.','Begin the first pull by driving through the front of the heels, raising the bar from the ground. The back angle should stay the same until the bar passes the knees.','Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. The feet should move forcefully to a split position, one foot forward one foot back. Receive the bar with your body as low as possible and the arms fully extended overhead.','Keeping the bar aligned over the front of the heels, your head and chest up, drive through heels of the feet to move to a standing position, bringing your feet together.','Carefully return the weight to floor.'], ARRAY['hamstrings'], ARRAY['calves','forearms','glutes','hamstrings','lower back','quadriceps','shoulders','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Split Squat with Dumbbells', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Position yourself into a staggered stance with the rear foot elevated and front foot forward.','Hold a dumbbell in each hand, letting them hang at the sides. This will be your starting position.','Begin by descending, flexing your knee and hip to lower your body down. Maintain good posture througout the movement. Keep the front knee in line with the foot as you perform the exercise.','At the bottom of the movement, drive through the heel to extend the knee and hip to return to the starting position.'], ARRAY['quadriceps'], ARRAY['glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Squat Jerk', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.','At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible. In the brief moment the feet are not actively driving against the platform, the athlete''s effort to push the bar up will drive them down. The feet should move forcefully to just outside the hips, turned out as necessary. Receive the bar with your body in a full squat and the arms fully extended overhead.','Keeping the bar aligned over the front of the heels, your head and chest up, drive throught heels of the feet to move to a standing position. Carefully return the weight to floor.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Squat with Bands', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Set up the bands on the sleeves, secured to either band pegs, the rack, or dumbbells so that there is appropriate tension.','Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings. Keep your head facing forward.','With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips as much as possible. Ideally, your shins should be perpendicular to the ground. Lower bar position necessitates a greater torso lean to keep the bar over the heels. Continue until you break parallel, which is defined as the crease of the hip being in line with the top of the knee.','Keeping the weight on your heels and pushing your feet and knees out, drive upward as you lead the movement with your head. Continue upward, maintaining tightness head to toe, until you have returned to the starting position.'], ARRAY['quadriceps'], ARRAY['adductors','calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Squat with Chains', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['To set up the chains, begin by looping the leader chain over the sleeves of the bar. The heavy chain should be attached using a snap hook. Adjust the length of the lead chain so that a few links are still on the floor at the top of the movement.','Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings. Keep your head facing forward.','With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips as much as possible. Ideally, your shins should be perpendicular to the ground. Lower bar position necessitates a greater torso lean to keep the bar over the heels. Continue until you break parallel, which is defined as the crease of the hip being in line with the top of the knee.','Keeping the weight on your heels and pushing your feet and knees out, drive upward as you lead the movement with your head. Continue upward, maintaining tightness head to toe, until you have returned to the starting position.'], ARRAY['quadriceps'], ARRAY['adductors','calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Squat with Plate Movers', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['To begin, first set the bar on a rack to just below shoulder level. Position a weight plate on the ground a couple feet back from the rack. Once the bar is loaded, step under it and place the back of your shoulders across it.','Hold on to the bar with both hands and lift it off the rack by first pushing with your legs and at the same time straighten your torso.','Step away from the rack and adopt a wide stance with the toes slightly pointed out, with one foot on the weight plate. Keep your head up at all times. This will be your starting position.','Begin to slowly lower the bar by bending the knees and hips. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees.','Raise the bar as you exhale by pushing the floor with the heels of your feet as you extend the hips and knees.','At the top of the movement, side step, bringing your feet together on the opposite side of the plate.','Using your inside foot, push the weight plate, sliding it across the floor to where you were just standing.','Place your inside foot on the weight plate, adopting a wide stance for the next repetition.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Squats - With Bands', 'bands', true, 'bands', 'beginner', 'push', 'compound', ARRAY['To start out, make sure that the exercise band is at an even split between both the left and right side of the body. To do this, use your hands to grab both sides of the band and place both feet in the middle of the band. Your feet should be shoulder width apart from each other.','When holding the bands, they should be the same height on each side. You should be using a pronated grip (palms facing forward) and have the handles of the bands next to your face for this exercise. This is the starting position.','Slowly start to bend the knees and lower the legs so that your thighs are parallel to the floor while exhaling.','Use the heel of your feet to push your body up to the starting position as you exhale.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Stairmaster', 'machine', true, 'machine', 'intermediate', NULL, NULL, ARRAY['To begin, step onto the stairmaster and select the desired option from the menu. You can choose a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise.','Pump your legs up and down in an established rhythm, driving the pedals down but not all the way to the floor. It is recommended that you maintain your grip on the handles so that you don''t fall. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.','Stairmasters offer convenience, cardiovascular benefits, and usually have less impact than running outside. They are typically much harder than other cardio equipment. A 150 lb person will typically burn over 300 calories in 30 minutes, compared to about 175 calories walking.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Alternating Dumbbell Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Stand with a dumbbell in each hand. Raise the dumbbells to your shoulders with your palms facing forward and your elbows pointed out. This will be your starting position.','Extend one arm to press the dumbbell straight up, keeping your off hand in place. Do not lean or jerk the weight during the movement.','After a brief pause, return the weight to the starting position.','Repeat for the opposite side, continuing to alternate between arms.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Barbell Calf Raise', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the bar on the back of your shoulders (slightly below the neck).','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. The knees should be kept with a slight bend; never locked. This will be your starting position. Tip: For better range of motion you may also place the ball of your feet on a wooden block but be careful as this option requires more balance and a sturdy block.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Barbell Press Behind Neck', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['This exercise is best performed inside a squat rack for easier pick up of the bar. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Your back should be kept straight while performing this exercise. This will be your starting position.','Elevate the barbell overhead by fully extending your arms while breathing out.','Hold the contraction for a second and lower the barbell back down to the starting position by inhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Bent-Over One-Arm Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['With a dumbbell in one hand and the palm facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.','The upper arm should be close to the torso and parallel to the floor while the forearm is pointing towards the floor as the hand holds the weight. Tip: There should be a 90-degree angle between the forearm and the upper arm. This is your starting position.','Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.','After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale.','Repeat the movement for the prescribed amount of repetitions.','Switch arms and repeat the exercise.'], ARRAY['triceps'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Bent-Over Two-Arm Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['With a dumbbell in each hand and the palms facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up. The upper arms should be close to the torso and parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights. Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.','Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arms are extended. Like many other arm exercises, only the forearm moves.','After a second contraction at the top, slowly lower the dumbbells back to their starting position as you inhale.','Repeat the movement for the prescribed amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Biceps Cable Curl', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Stand up with your torso upright while holding a cable curl bar that is attached to a low pulley. Grab the cable bar at shoulder width and keep the elbows close to the torso. The palm of your hands should be facing up (supinated grip). This will be your starting position.','While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.','Slowly begin to bring the curl bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Bradford Press', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Place a loaded bar at shoulder level in a rack. With a pronated grip at shoulder width, begin with the bar racked across the front of your shoulders. This is your starting position.','Initiate the lift by extending the elbows to press the bar overhead. Avoid locking out the elbow as you move the weight behind your head.','Lower the bar down to the back of the head until your elbow forms a right angle.','Lift the bar back over your head by extending the elbows','Lower the bar down to the starting position.','Alternate in this manner until you complete the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Cable Chest Press', 'cable', true, 'cable', 'beginner', 'push', 'compound', ARRAY['Position dual pulleys to chest height and select an appropriate weight. Stand a foot or two in front of the cables, holding one in each hand. You can stagger your stance for better stability.','Position the upper arm at a 90 degree angle with the shoulder blades together. This will be your starting position.','Keeping the rest of the body stationary, extend through the elbows to press the handles forward, drawing them together in front of you.','Pause at the top of the motion, and return to the starting position.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Cable Lift', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Connect a standard handle on a tower, and move the cable to the lowest pulley position.','With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Your outstretched arm should be aligned with the cable.','With your feet positioned shoulder width apart, squat down and grab the handle with both hands. Your arms should still be fully extended.','In one motion, pull the handle up and across your body until your arms are in a fully-extended position above your head.','Keep your back straight and your arms close to your body as you pivot your back foot and straighten your legs to get a full range of motion.','Retract your arms and then your body. Return to the neutral position in a slow and controlled manner.','Repeat to failure.','Then, reposition and repeat the same series of movements on the opposite side.'], ARRAY['abdominals'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Cable Wood Chop', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Connect a standard handle to a tower, and move the cable to the highest pulley position.','With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Your outstretched arm should be aligned with the cable.','With your feet positioned shoulder width apart, reach upward with your other hand and grab the handle with both hands. Your arms should still be fully extended.','In one motion, pull the handle down and across your body to your front knee while rotating your torso.','Keep your back and arms straight and core tight while you pivot your back foot and bend your knees to get a full range of motion.','Maintain your stance and straight arms. Return to the neutral position in a slow and controlled manner.','Repeat to failure.','Then, reposition and repeat the same series of movements on the opposite side.'], ARRAY['abdominals'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Calf Raises', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Adjust the padded lever of the calf raise machine to fit your height.','Place your shoulders under the pads provided and position your toes facing forward (or using any of the two other positions described at the beginning of the chapter). The balls of your feet should be secured on top of the calf block with the heels extending off it. Push the lever up by extending your hips and knees until your torso is standing erect. The knees should be kept with a slight bend; never locked. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Concentration Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Taking a dumbbell in your working hand, lean forward. Allow your working arm to hang perpendicular to the ground with the elbow pointing out. This will be your starting position.','Flex the elbow to curl the weight, keeping the upper arm stationary. At the top of the repetition, flex the biceps and pause.','Lower the dumbbell back to the starting position.','Repeat the movement for the prescribed amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Dumbbell Calf Raise', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'isolation', ARRAY['Stand with your torso upright holding two dumbbells in your hands by your sides. Place the ball of the foot on a sturdy and stable wooden board (that is around 2-3 inches tall) while your heels extend off and touch the floor. This will be your starting position.','With the toes pointing either straight (to hit all parts equally), inwards (for emphasis on the outer head) or outwards (for emphasis on the inner head), raise the heels off the floor as you exhale by contracting the calves. Hold the top contraction for a second.','As you inhale, go back to the starting position by slowly lowering the heels.','Repeat for the recommended amount of times.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Dumbbell Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Standing with your feet shoulder width apart, take a dumbbell in each hand. Raise the dumbbells to head height, the elbows out and about 90 degrees. This will be your starting position.','Maintaining strict technique with no leg drive or leaning back, extend through the elbow to raise the weights together directly above your head.','Pause, and slowly return the weight to the starting position.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Dumbbell Reverse Curl', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['To begin, stand straight with a dumbbell in each hand using a pronated grip (palms facing down). Your arms should be fully extended while your feet are shoulder width apart from each other. This is the starting position.','While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the muscle.','Slowly begin to bring the dumbbells back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Dumbbell Straight-Arm Front Delt Raise Above Head', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'isolation', ARRAY['Hold the dumbbells in front of your thighs, palms facing your thighs.','Keep your arms straight with a slight bend at the elbows but keep them locked. This will be your starting position.','Raise the dumbbells in a semicircular motion to arm''s length overhead as you exhale.','Slowly return to the starting position using the same path as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['To begin, stand up with a dumbbell held by both hands. Your feet should be about shoulder width apart from each other. Slowly use both hands to grab the dumbbell and lift it over your head until both arms are fully extended.','The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hands should be facing up towards the ceiling. This will be your starting position.','Keeping your upper arms close to your head with elbows in and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.','Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Dumbbell Upright Row', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Grasp a dumbbell in each hand with a pronated (palms forward) grip that is slightly less than shoulder width. The dumbbells should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.','Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be close to the body as you move it up and the elbows should drive the motion. Continue to lift them until they nearly touch your chin. Tip: Your elbows should drive the motion. As you lift the dumbbells, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the dumbbells back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY['biceps','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Front Barbell Raise Over Head', 'barbell', true, 'barbell', 'intermediate', 'push', 'isolation', ARRAY['To begin, stand straight with a barbell in your hands. You should grip the bar with palms facing down and a closer than shoulder width grip apart from each other.','Your feet should be shoulder width apart from each other. Your elbows should be slightly bent. This is the starting position.','Lift the barbell up until it is directly over your head while exhaling. Make sure to keep your elbows slightly bent when performing each repetition.','Once you feel the contraction, begin to lower the barbell back down to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Inner-Biceps Curl', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['Stand up with a dumbbell in each hand being held at arms length. The elbows should be close to the torso. Your legs should be at about shoulder''s width apart from each other.','Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.','While holding the upper arms stationary, curl the weights out while contracting the biceps as you breathe out. Your wrist should turn so that when the weights are fully elevated you have supinated grip (palms facing up).','Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: Keep the forearms aligned with your outer deltoids.','Hold the contracted position for a second as you squeeze the biceps.','Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate the wrists as you lower the weight in order to switch back to a neutral grip.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Leg Curl', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['Adjust the machine lever to fit your height and lie with your torso bent at the waist facing forward around 30-45 degrees (since an angled position is more favorable for hamstrings recruitment) with the pad of the lever on the back of your right leg (just a few inches under the calves) and the front of the right leg on top of the machine pad.','Keeping the torso bent forward, ensure your leg is fully stretched and grab the side handles of the machine. Position your toes straight. This will be your starting position.','As you exhale, curl your right leg up as far as possible without lifting the upper leg from the pad. Once you hit the fully contracted position, hold it for a second.','As you inhale, bring the legs back to the initial position. Repeat for the recommended amount of repetitions.','Perform the same exercise now for the left leg.'], ARRAY['hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Long Jump', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['This drill is best done in sand or other soft landing surface. Ensure that you are able to measure distance. Stand in a partial squat stance with feet shoulder width apart.','Utilizing a big arm swing and a countermovement of the legs, jump forward as far as you can.','Attempt to land with your feet out in front you, reaching as far as possible with your legs.','Measure the distance from your landing point to the starting point and track results.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Low-Pulley Deltoid Raise', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['Start by standing to the right side of a low pulley row. Use your left hand to come across the body and grab a single handle attached to the low pulley with a pronated grip (palms facing down). Rest your arm in front of you. Your right hand should grab the machine for better support and balance.','Make sure that your back is erect and your feet are shoulder width apart from each other. This is the starting position.','Begin to use the left hand and come across your body out until it is elevated to shoulder height while exhaling.','Feel the contraction at the top for a second and begin to slowly lower the handle back down to the original starting position while inhaling.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the exercise.'], ARRAY['shoulders'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Low-Pulley One-Arm Triceps Extension', 'cable', true, 'cable', 'intermediate', 'push', 'isolation', ARRAY['Grab a single handle with your left arm next to the low pulley machine. Turn away from the machine keeping the handle to the side of your body with your arm fully extended. Now use both hands to elevate the single handle directly above the head with the palm facing forward. Keep your upper arm completely vertical (perpendicular to the floor) and put your right hand on your left elbow to help keep it steady. This is the starting position.','Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.','Go back to the starting position by using the triceps to raise the single handle. Breathe out as you perform this step.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the exercise.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Military Press', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Start by placing a barbell that is about chest high on a squat rack. Once you have selected the weights, grab the barbell using a pronated (palms facing forward) grip. Make sure to grip the bar wider than shoulder width apart from each other.','Slightly bend the knees and place the barbell on your collar bone. Lift the barbell up keeping it lying on your chest. Take a step back and position your feet shoulder width apart from each other.','Once you pick up the barbell with the correct grip length, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position.','Lower the bar down to the collarbone slowly as you inhale.','Lift the bar back up to the starting position as you exhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Olympic Plate Hand Squeeze', 'other', true, 'other', 'beginner', 'static', 'isolation', ARRAY['To begin, stand straight while holding a weight plate by the ridge at arm''s length in each hand using a neutral grip (palms facing in). You feet should be shoulder width apart from each other. This will be your starting position.','Lower the plates until the fingers are nearly extended but can still hold weights. Inhale as you lower the plates.','Now raise the plates back to the starting position as you exhale by closing your hands.','Repeat for the recommended amount of repetitions prescribed in your program.'], ARRAY['forearms'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing One-Arm Cable Curl', 'cable', true, 'cable', 'intermediate', 'pull', 'isolation', ARRAY['Start out by grabbing single handle next to the low pulley machine. Make sure you are far enough from the machine so that your arm is supporting the weight.','Make sure that your upper arm is stationary, perpendicular to the floor with elbows in and palms facing forward. Your non lifting arm should be grabbing your waist. This will allow you to keep your balance.','Slowly begin to curl the single handle upwards while keeping the upper arm stationary until your forearm touches your bicep while exhaling. Tip: Only the forearm should move.','Hold the contraction position as you squeeze the bicep and then lower the single handle back down to the starting position as you inhale.','Repeat for the recommended amount of repetitions.','Switch arms while performing this exercise.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing One-Arm Dumbbell Curl Over Incline Bench', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand on the back side of an incline bench as if you were going to be a spotter for someone. Have a dumbbell in one hand and rest it across the incline bench with a supinated (palms up) grip.','Position your non lifting hand at the corner or side of the incline bench. The chest should be pressed against the top part of the incline and your feet should be pressed against the floor at a wide stance. This is the starting position.','While holding the upper arm stationary, curl the dumbbell upward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a second.','Slowly begin to bring the dumbbells back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.','Switch arms while performing this exercise.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing One-Arm Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['To begin, stand up with a dumbbell held in one hand. Your feet should be about shoulder width apart from each other. Now fully extend the arm with the dumbbell over your head. Tip: The small finger of your hand should be facing the ceiling and the palm of your hand should be facing forward. The dumbbell should be above your head.','This will be your starting position.','Keeping your upper arm close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearm touch your bicep. Tip: The upper arm should remain stationary and only the forearm should move. Breathe in as you perform this step.','Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the exercise.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Overhead Barbell Triceps Extension', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['To begin, stand up holding a barbell or e-z bar using a pronated grip (palms facing forward) with your hands closer than shoulder width apart from each other. Your feet should be about shoulder width apart.','Now elevate the barbell above your head until your arms are fully extended. Keep your elbows in. This will be your starting position.','Keeping your upper arms close to your head and elbows in, perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.','Go back to the starting position by using the triceps to raise the barbell. Breathe out as you perform this step.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Palm-In One-Arm Dumbbell Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Start by having a dumbbell in one hand with your arm fully extended to the side using a neutral grip. Use your other arm to hold on to an incline bench to keep your balance.','Your feet should be shoulder width apart from each other. Now slowly lift the dumbbell up until you create a 90 degree angle with your arm. Note: Your forearm should be perpendicular to the floor. Continue to maintain a neutral grip throughout the entire exercise.','Slowly lift the dumbbell up until your arm is fully extended. This the starting position.','While inhaling lower the weight down until your arm is at a 90 degree angle again.','Feel the contraction for a second and then lift the weight back up towards the starting position while exhaling. Remember to hold on to the incline bench and keep your feet positioned to keep balance during the exercise.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the exercise.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Palms-In Dumbbell Press', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Start by having a dumbbell in each hand with your arm fully extended to the side using a neutral grip. Your feet should be shoulder width apart from each other. Now slowly lift the dumbbells up until you create a 90 degree angle with your arms. Note: Your forearms should be perpendicular to the floor. This the starting position.','Continue to maintain a neutral grip throughout the entire exercise. Slowly lift the dumbbells up until your arms are fully extended.','While inhaling lower the weights down until your arm is at a 90 degree angle again.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Palms-Up Barbell Behind The Back Wrist Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Start by standing straight and holding a barbell behind your glutes at arm''s length while using a pronated grip (palms will be facing back away from the glutes) and having your hands shoulder width apart from each other.','You should be looking straight forward while your feet are shoulder width apart from each other. This is the starting position.','While exhaling, slowly elevate the barbell up by curling your wrist in a semi-circular motion towards the ceiling. Note: Your wrist should be the only body part moving for this exercise.','Hold the contraction for a second and lower the barbell back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.','When finished, lower the barbell down to the squat rack or the floor by bending the knees. Tip: It is easiest to either pick it up from a squat rack or have a partner hand it to you.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Rope Crunch', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Attach a rope to a high pulley and select an appropriate weight.','Stand with your back to the cable tower. Take the rope with both hands over your shoulders, holding it to your upper chest. This will be your starting position.','Perform the movement by flexing the spine, crunching the weight down as far as you can.','Hold the peak contraction for a moment before returning to the starting position.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Towel Triceps Extension', 'body only', true, 'body only', 'beginner', 'push', 'isolation', ARRAY['To begin, stand up with both arms fully extended above the head holding one end of a towel with both hands. Your elbows should be in and the arms perpendicular to the floor with the palms facing each other while your feet should be shoulder width apart from each other. This is the starting position.','Now communicate with your partner so that he/she can grip the other side of the towel to apply resistance. Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.','Go back to the starting position by using the triceps to raise the towel. Breathe out as you perform this step.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Standing Two-Arm Overhead Throw', 'medicine ball', true, 'medicine ball', 'beginner', 'pull', 'compound', ARRAY['Stand with your feet shoulder width apart holding a medicine ball in both hands. To begin, reach the medicine ball deep behind your head as you bend the knees slightly and lean back.','Violently throw the ball forward, flexing at the hip and using your whole body to complete the movement.','The medicine ball can be thrown to a partner or to a wall, receiving it as it bounces back.'], ARRAY['shoulders'], ARRAY['chest','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Star Jump', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.','To initiate the move, squat down halfway and explode back up as high as possible. Fully extend your entire body, spreading your legs and arms away from the body.','As you land, bring your limbs back in and absorb your impact through the legs.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Step-up with Knee Raise', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Stand facing a box or bench of an appropriate height with your feet together. This will be your starting position.','Begin the movement by stepping up, putting your left foot on the top of the bench. Extend through the hip and knee of your front leg to stand up on the box. As you stand on the box with your left leg, flex your right knee and hip, bringing your knee as high as you can.','Reverse this motion to step down off the box, and then repeat the sequence on the opposite leg.'], ARRAY['glutes'], ARRAY['hamstrings','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Step Mill', 'machine', true, 'machine', 'intermediate', NULL, NULL, ARRAY['To begin, step onto the stepmill and select the desired option from the menu. You can choose a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Use caution so that you don''t trip as you climb the stairs. It is recommended that you maintain your grip on the handles so that you don''t fall.','Stepmills offer convenience, cardiovascular benefits, and usually have less impact than running outside while offering a similar rate of calories burned. They are typically much harder than other cardio equipment. A 150 lb person will typically burn over 300 calories in 30 minutes, compared to about 175 calories walking.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Stiff-Legged Barbell Deadlift', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Grasp a bar using an overhand grip (palms facing down). You may need some wrist wraps if using a significant amount of weight.','Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.','Keeping the knees stationary, lower the barbell to over the top of your feet by bending at the hips while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Inhale as you perform this movement.','Start bringing your torso up straight again by extending your hips until you are back at the starting position. Exhale as you perform this movement.','Repeat for the recommended amount of repetitions.'], ARRAY['hamstrings'], ARRAY['glutes','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Stiff-Legged Dumbbell Deadlift', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Grasp a couple of dumbbells holding them by your side at arm''s length.','Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.','Keeping the knees stationary, lower the dumbbells to over the top of your feet by bending at the waist while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Exhale as you perform this movement','Start bringing your torso up straight again by extending your hips and waist until you are back at the starting position. Inhale as you perform this movement.','Repeat for the recommended amount of repetitions.'], ARRAY['hamstrings'], ARRAY['glutes','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Stiff Leg Barbell Good Morning', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position.','Keeping your legs stationary, move your torso forward by bending at the hips while inhaling. Lower your torso until it is parallel with the floor.','Begin to raise the bar as you exhale by elevating your torso back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['lower back'], ARRAY['glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Straight-Arm Dumbbell Pullover', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'compound', ARRAY['Place a dumbbell standing up on a flat bench.','Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.','Grasp the dumbbell with both hands and hold it straight over your chest at arms length. Both palms should be pressing against the underside one of the sides of the dumbbell. This will be your starting position.
Caution: Always ensure that the dumbbell used for this exercise is secure. Using a dumbbell with loose plates can result in the dumbbell falling apart and falling on your face.','While keeping your arms straight, lower the weight slowly in an arc behind your head while breathing in until you feel a stretch on the chest.','At that point, bring the dumbbell back to the starting position using the arc through which the weight was lowered and exhale as you perform this movement.','Hold the weight on the initial position for a second and repeat the motion for the prescribed number of repetitions.'], ARRAY['chest'], ARRAY['lats','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Straight-Arm Pulldown', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['You will start by grabbing the wide bar from the top pulley of a pulldown machine and using a wider than shoulder-width pronated (palms down) grip. Step backwards two feet or so.','Bend your torso forward at the waist by around 30-degrees with your arms fully extended in front of you and a slight bend at the elbows. If your arms are not fully extended then you need to step a bit more backwards until they are. Once your arms are fully extended and your torso is slightly bent at the waist, tighten the lats and then you are ready to begin.','While keeping the arms straight, pull the bar down by contracting the lats until your hands are next to the side of the thighs. Breathe out as you perform this step.','While keeping the arms straight, go back to the starting position while breathing in.','Repeat for the recommended amount of repetitions.'], ARRAY['lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Straight Bar Bench Mid Rows', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Place a loaded barbell on the end of a bench. Standing on the bench behind the bar, take a medium, pronated grip. Stand with your hips back and chest up, maintaining a neutral spine. This will be your starting position.','Row the bar to your torso by retracting the shoulder blades and flexing the elbows. Use a controlled movement with no jerking.','After a brief pause, slowly return the bar to the starting position, ensuring to go all the way down.'], ARRAY['middle back'], ARRAY['biceps','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Straight Raises on Incline Bench', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['Place a bar on the ground behind the head of an incline bench.','Lay on the bench face down. With a pronated grip, pick the barbell up from the floor, keeping your arms straight. Allow the bar to hang straight down. This will be your starting position.','To begin, raise the barbell out in front of your head while keeping your arms extended.','Return to the starting position.'], ARRAY['shoulders'], ARRAY['traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Stride Jump Crossover', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Stand to the side of a box with your inside foot on top of it, close to the edge.','Begin by swinging the arms upward as you push through the top leg, jumping upward as high as possible. Attempt to drive the opposite knee upward.','Land in the opposite position that you started, on the opposite side of the box. The foot that was initially on the box will now be on the ground, with the opposite foot now on the box.','Repeat the movement, crossing back over to the other side.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sumo Deadlift', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.','Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.','As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.','Return the weight to the ground by bending at the hips and controlling the weight on the way down.'], ARRAY['hamstrings'], ARRAY['adductors','forearms','glutes','lower back','middle back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sumo Deadlift with Bands', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['To deadlift with short bands, simply loop them over the bar before you start, and step into them to set up. Ensure that they under the back half of your foot, directly where you are driving into the floor.','Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip.','Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.','As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.','Return the weight to the ground by bending at the hips and controlling the weight on the way down.'], ARRAY['hamstrings'], ARRAY['adductors','forearms','glutes','lower back','middle back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sumo Deadlift with Chains', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['You can attach the chains to the sleeves of the bar, or just drape the middle over the bar so there is a greater weight increase as you lift. Attempt to keep the ends of the chains away from the plates so you don''t hit them when you lower the weight.','Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.','Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.','As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.','Return the weight to the ground by bending at the hips and controlling the weight on the way down.'], ARRAY['hamstrings'], ARRAY['abductors','adductors','forearms','glutes','lower back','middle back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Supine Chest Throw', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['This drill is great for chest passes when you lack a partner or a wall of sufficient strength. Lay on the ground on your back with your knees bent.','Begin with the ball on your chest, held with both hands on the bottom.','Explode up, extending through the elbow to throw the ball directly above you as high as possible.','Catch the ball with both hands as it comes down.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Supine One-Arm Overhead Throw', 'medicine ball', true, 'medicine ball', 'beginner', 'pull', 'compound', ARRAY['Lay on the ground on your back with your knees bent. Hold the ball with one hand, extending the arm fully behind your head. This will be your starting position.','Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.','The ball can be thrown to a partner or bounced off of a wall.'], ARRAY['abdominals'], ARRAY['chest','lats','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Supine Two-Arm Overhead Throw', 'medicine ball', true, 'medicine ball', 'beginner', 'pull', 'compound', ARRAY['Lay on the ground on your back with your knees bent.','Hold the ball with both hands, extending the arms fully behind your head. This will be your starting position.','Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.','The ball can be thrown to a partner or bounced off of a wall.'], ARRAY['abdominals'], ARRAY['chest','lats','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Suspended Fallout', 'other', true, 'other', 'intermediate', 'pull', 'isolation', ARRAY['Adjust the straps so the handles are at an appropriate height, below waist level.','Begin standing and grasping the handles. Lean into the straps, moving to an incline push-up position. This will be your starting position.','Keeping your arms straight, lean further into the suspension straps, bringing your body closer to the ground, allowing your shoulders to extend, raising your arms up and over your head.','Maintain a neutral spine and keep the rest of your body straight, your shoulders being the only joints allowed to move.','Pause during the peak contraction, and then return to the starting position.'], ARRAY['abdominals'], ARRAY['chest','lower back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Suspended Push-Up', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Anchor your suspension straps securely to the top of a rack or other object.','Leaning into the straps, take a handle in each hand and move into a push-up plank position. You should be as close to parallel to the ground as you can manage with your arms fully extended, maintaining good posture.','Maintaining a straight, rigid torso, descend slowly by allowing the elbows to flex.','Continue until your elbows break 90 degrees, pausing before you extend to return to the starting position.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Suspended Reverse Crunch', 'other', true, 'other', 'beginner', 'pull', 'isolation', ARRAY['Secure a set of suspension straps with the handles hanging about a foot off of the ground. Move yourself into a pushup plank position facing away from the rack.','Place your feet into the handles. You should maintain a straight posture, not allowing the hips to sag. This will be your starting position.','Begin the movement by flexing the knees and hips, drawing the knees to your torso. As you do so, anteriorly tilt your pelvis, allowing your spine to flex.','At the top of the controlled motion, return to the starting position.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Suspended Row', 'other', true, 'other', 'beginner', 'pull', 'compound', ARRAY['Suspend your straps at around chest height. Take a handle in each hand and lean back. Keep your body erect and your head and chest up. Your arms should be fully extended. This will be your starting position.','Begin by flexing the elbow to initiate the movement. Protract your shoulder blades as you do so.','At the completion of the motion pause, and then return to the starting position.'], ARRAY['middle back'], ARRAY['biceps','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Suspended Split Squat', 'other', true, 'other', 'intermediate', 'push', 'compound', ARRAY['Suspend your straps so the handles are 18-30 inches from the floor.','Facing away from the setup, place your rear foot into the handle behind you. Keep your head looking forward and your chest up, with your knee slightly bent. This will be your starting position.','Descend by flexing the knee and hips, lowering yourself to the ground. Keep your weight on the heel of your foot and maintain your posture throughout the exercise.','At the bottom of the movement, reverse the motion, extending through the hip and knee to return to the starting position.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Svend Press', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Begin in a standing position.','Press two lightweight plates together with your hands. Hold the plates together close to your chest to create an isometric contraction in your chest muscles. Your fingers should be pointed forward. This is your starting position.','Squeeze the plates between your palms and extend your arms directly out in front of you in a controlled motion.','Pause at the top of the motion, and then slowly return to the starting position.'], ARRAY['chest'], ARRAY['forearms','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('T-Bar Row with Handle', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Position a bar into a landmine or in a corner to keep it from moving. Load an appropriate weight onto your end.','Stand over the bar, and position a Double D row handle around the bar next to the collar. Using your hips and legs, rise to a standing position.','Assume a wide stance with your hips back and your chest up. Your arms should be extended. This will be your starting position.','Pull the weight to your upper abdomen by retracting the shoulder blades and flexing the elbows. Do not jerk the weight or cheat during the movement.','After a brief pause, return to the starting position.'], ARRAY['middle back'], ARRAY['biceps','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Tate Press', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'isolation', ARRAY['Lie down on a flat bench with a dumbbell in each hand on top of your thighs. The palms of your hand will be facing each other.','By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them in front of you at shoulder width. Note: when holding the dumbbells in front of you, make sure your arms are wider than shoulder width apart from each other using a pronated (palms forward) grip. Allow your elbows to point out. This is your starting position.','Keeping the upper arms stationary, slowly move the dumbbells in and down in a semi circular motion until they touch the upper chest while inhaling. Keep full control of the dumbbells at all times and do not move the upper arms nor rest the dumbbells on the chest.','As you breathe out, move the dumbbells up using your triceps and the same semi-circular motion but in reverse. Attempt to keep the dumbbells together as they move up. Lock your arms in the contracted position, hold for a second and then start coming down again slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions of your training program.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
